import{_ as t}from"./chunks/cube-sandbox-arch.CvZrsuBd.js";import{_ as r,o as a,c as o,a0 as i}from"./chunks/framework.CWk8AOcY.js";const b=JSON.parse('{"title":"Architecture Overview","description":"","frontmatter":{},"headers":[],"relativePath":"en/architecture/overview.md","filePath":"architecture/overview.md"}'),n={name:"en/architecture/overview.md"};function s(c,e,l,h,d,u){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h1><p>Cube Sandbox follows a clear layered architecture from top to bottom.</p><h2 id="layered-architecture" tabindex="-1">Layered Architecture <a class="header-anchor" href="#layered-architecture" aria-label="Permalink to &quot;Layered Architecture&quot;">​</a></h2><p><img src="'+t+'" alt="Cube Sandbox Architecture"></p><h2 id="key-components" tabindex="-1">Key Components <a class="header-anchor" href="#key-components" aria-label="Permalink to &quot;Key Components&quot;">​</a></h2><ol><li><strong>CubeAPI</strong>: E2B-compatible REST API gateway. Switch from E2B Cloud to Cube Sandbox seamlessly by simply replacing environment variables such as the URL.</li><li><strong>CubeMaster</strong>: Orchestration scheduler that receives E2B API requests and dispatches them to the corresponding Cubelet, handling resource scheduling and cluster state management.</li><li><strong>CubeProxy</strong>: Reverse proxy and request routing component that parses the <code>&lt;port&gt;-&lt;sandbox_id&gt;.&lt;domain&gt;</code> format in the Host header to forward SDK client requests to the target sandbox instance.</li><li><strong>Cubelet</strong>: Node-local scheduling component that manages the full lifecycle of all sandbox instances on a single node.</li><li><strong>CubeVS</strong>: eBPF-based kernel-level packet forwarding, providing comprehensive network isolation and security policy enforcement.</li><li><strong>CubeHypervisor &amp; CubeShim</strong>: The virtualization layer of Cube Sandbox. CubeHypervisor manages KVM MicroVMs, CubeShim implements the containerd Shim v2 API to integrate sandboxes into the container runtime.</li></ol>',6)])])}const g=r(n,[["render",s]]);export{b as __pageData,g as default};
